/// <reference path="../online-streaming-provider.d.ts" />
/// <reference path="../core.d.ts" />

class Provider {

    baseUrl = "https://nimegami.id"

    getSettings(): Settings {
        return {
            episodeServers: ["berkasdrive"],
            supportsDub: false,
        }
    }

    /**
     * Search for anime on nimegami.id
     * Uses WordPress standard search: GET /?s={query}
     */
    async search(opts: SearchOptions): Promise<SearchResult[]> {
        const query = encodeURIComponent(opts.query)
        const url = `${this.baseUrl}/?s=${query}`

        const res = await fetch(url)
        if (!res.ok) {
            console.error("Nimegami search failed:", res.status, res.statusText)
            return []
        }

        const html = await res.text()
        const $ = LoadDoc(html)
        const results: SearchResult[] = []

        $("article").each((_: any, el: any) => {
            try {
                // Title and URL from h2[itemprop="name"] > a
                const titleEl = el.find("h2 a").first()
                const title = titleEl.text().trim()
                const articleUrl = titleEl.attr("href") || ""

                if (!title || !articleUrl) return

                // Extract the slug from the URL to use as ID
                // e.g. https://nimegami.id/tensei-shitara-slime-datta-ken-sub-indo-5/
                const slug = this.extractSlug(articleUrl)
                if (!slug) return

                results.push({
                    id: slug,
                    title: title,
                    url: articleUrl,
                    subOrDub: "sub",
                })
            } catch (e) {
                console.error("Error parsing search result:", e)
            }
        })

        return results
    }

    /**
     * Find all episodes for a given anime
     * The id is the anime page slug
     */
    async findEpisodes(id: string): Promise<EpisodeDetails[]> {
        const url = `${this.baseUrl}/${id}/`

        const res = await fetch(url)
        if (!res.ok) {
            throw new Error(`Failed to fetch anime page: ${res.status}`)
        }

        const html = await res.text()
        const $ = LoadDoc(html)
        const episodes: EpisodeDetails[] = []

        // Episodes are in li.select-eps inside div.list_eps_stream
        $("li.select-eps").each((_: any, el: any) => {
            try {
                const dataAttr = el.attr("data")
                if (!dataAttr) return

                // Extract episode number from id attribute (e.g., "play_eps_1")
                const epsId = el.attr("id") || ""
                let episodeNumber = 0

                if (epsId) {
                    const match = epsId.match(/play_eps_(\d+)/)
                    if (match && match[1]) {
                        episodeNumber = parseInt(match[1], 10)
                    }
                }

                // Fallback: try to extract from text
                if (episodeNumber === 0) {
                    const text = el.text().trim()
                    const numMatch = text.match(/(\d+)/)
                    if (numMatch && numMatch[1]) {
                        episodeNumber = parseInt(numMatch[1], 10)
                    }
                }

                if (episodeNumber === 0) return

                episodes.push({
                    id: `${id}$${episodeNumber}`,
                    number: episodeNumber,
                    url: url,
                    title: `Episode ${episodeNumber}`,
                })
            } catch (e) {
                console.error("Error parsing episode:", e)
            }
        })

        // Sort by episode number
        episodes.sort((a, b) => a.number - b.number)

        // Normalize episode numbers if they don't start from 1
        if (episodes.length > 0) {
            const lowest = episodes[0].number
            if (lowest > 1) {
                for (let i = 0; i < episodes.length; i++) {
                    episodes[i].number = episodes[i].number - lowest + 1
                }
            }
        }

        // Filter out decimal episode numbers
        const filtered = episodes.filter(ep => Number.isInteger(ep.number))

        if (filtered.length === 0) {
            throw new Error("No episodes found.")
        }

        return filtered
    }

    /**
     * Find episode server / streaming sources
     * Decodes the base64-encoded JSON from the episode's li.select-eps data attribute
     */
    async findEpisodeServer(episode: EpisodeDetails, _server: string): Promise<EpisodeServer> {
        const parts = episode.id.split("$")
        const animeSlug = parts[0]
        const episodeNumber = parseInt(parts[1], 10)

        const url = `${this.baseUrl}/${animeSlug}/`

        const res = await fetch(url)
        if (!res.ok) {
            throw new Error(`Failed to fetch anime page: ${res.status}`)
        }

        const html = await res.text()
        const $ = LoadDoc(html)

        const result: EpisodeServer = {
            server: "berkasdrive",
            headers: {},
            videoSources: [],
        }

        // Find the matching episode li element
        const targetId = `play_eps_${episodeNumber}`
        let dataAttr = ""

        $("li.select-eps").each((_: any, el: any) => {
            const elId = el.attr("id") || ""
            if (elId === targetId) {
                dataAttr = el.attr("data") || ""
            }
        })

        // If not found by id, try by index (episode number - 1)
        if (!dataAttr) {
            const allEps = $("li.select-eps")
            const targetIndex = episodeNumber - 1
            allEps.each((i: any, el: any) => {
                if (i === targetIndex) {
                    dataAttr = el.attr("data") || ""
                }
            })
        }

        if (!dataAttr) {
            throw new Error(`Episode ${episodeNumber} not found on the page.`)
        }

        // Decode base64 data attribute
        let decodedJson = ""
        try {
            // Use CryptoJS for base64 decoding
            const decoded = CryptoJS.enc.Base64.parse(dataAttr)
            decodedJson = CryptoJS.enc.Utf8.stringify(decoded)
        } catch (e) {
            console.error("Failed to decode base64 data:", e)
            throw new Error("Failed to decode episode streaming data.")
        }

        if (!decodedJson) {
            throw new Error("Decoded episode data is empty.")
        }

        // Parse the JSON
        // Expected format: [{"format":"360p","url":["https://dl.berkasdrive.com/streaming/?id=..."]}, ...]
        let streamData: { format: string; url: string[] }[] = []
        try {
            streamData = JSON.parse(decodedJson) as { format: string; url: string[] }[]
        } catch (e) {
            console.error("Failed to parse episode JSON:", e, decodedJson)
            throw new Error("Failed to parse episode streaming data.")
        }

        // Build video sources from each resolution
        // We need to fetch each berkasdrive streaming page to extract the direct mp4 URL
        for (const entry of streamData) {
            if (!entry.url || entry.url.length === 0) continue

            for (let i = 0; i < entry.url.length; i++) {
                const streamUrl = entry.url[i]
                if (!streamUrl) continue

                const serverLabel = entry.url.length > 1 ? ` Server ${i + 1}` : ""
                const quality = `${entry.format}${serverLabel}`

                // Fetch the berkasdrive streaming page and extract the direct mp4 URL
                const directUrl = await this.extractDirectVideoUrl(streamUrl)
                if (!directUrl) {
                    console.error(`Failed to extract direct URL for ${quality}:`, streamUrl)
                    continue
                }

                result.videoSources.push({
                    url: directUrl,
                    type: "mp4",
                    quality: quality,
                    subtitles: [],
                })
            }
        }

        if (result.videoSources.length === 0) {
            throw new Error("No streaming sources found for this episode.")
        }

        return result
    }

    /**
     * Fetch a berkasdrive streaming page and extract the direct mp4 URL
     * The streaming page uses a Plyr player with a <source> tag containing the actual mp4 URL
     */
    private async extractDirectVideoUrl(streamPageUrl: string): Promise<string> {
        try {
            const res = await fetch(streamPageUrl)
            if (!res.ok) {
                console.error("Failed to fetch streaming page:", res.status)
                return ""
            }

            const html = await res.text()
            const $ = LoadDoc(html)

            // Look for <source> element inside <video> tag
            let directUrl = ""

            $("video source").each((_: any, el: any) => {
                const src = el.attr("src") || ""
                if (src && (src.includes(".mp4") || src.includes("berkasdrive") || src.includes("miterequest"))) {
                    directUrl = src
                }
            })

            // Fallback: try to find the src attribute on the video element itself
            if (!directUrl) {
                $("video").each((_: any, el: any) => {
                    const src = el.attr("src") || ""
                    if (src && src.length > 0) {
                        directUrl = src
                    }
                })
            }

            // Fallback: look for mp4 URL in page source using regex
            if (!directUrl) {
                const mp4Match = html.match(/https?:\/\/[^"'\s]+\.mp4[^"'\s]*/i)
                if (mp4Match && mp4Match[0]) {
                    directUrl = mp4Match[0]
                }
            }

            return directUrl
        } catch (e) {
            console.error("Error extracting direct video URL:", e)
            return ""
        }
    }

    /**
     * Extract slug from a nimegami.id URL
     * e.g. "https://nimegami.id/tensei-shitara-slime-datta-ken-sub-indo-5/" -> "tensei-shitara-slime-datta-ken-sub-indo-5"
     */
    private extractSlug(url: string): string {
        try {
            // Remove trailing slash
            let cleaned = url.replace(/\/+$/, "")
            // Get the last path segment
            const parts = cleaned.split("/")
            return parts[parts.length - 1] || ""
        } catch (e) {
            return ""
        }
    }
}

/// <reference path="../manga-provider.d.ts" />
/// <reference path="../core.d.ts" />

class Provider {

    private api = "https://09.shinigami.asia"

    getSettings(): Settings {
        return {
            supportsMultiLanguage: false,
            supportsMultiScanlator: false,
        }
    }

    /**
     * Search for manga on shinigami.asia
     * Uses the search page and scrapes results
     */
    async search(opts: QueryOptions): Promise<SearchResult[]> {
        const query = encodeURIComponent(opts.query)
        const url = `${this.api}/search?q=${query}`

        const res = await fetch(url)
        if (!res.ok) {
            console.error("Shinigami search failed:", res.status, res.statusText)
            return []
        }

        const html = await res.text()
        const $ = LoadDoc(html)
        const results: SearchResult[] = []

        // Parse manga from search results
        // Look for links that match series pattern
        $("a[href*='/series/']").each((_: any, el: any) => {
            try {
                const href = el.attr("href") || ""
                if (!href.includes("/series/")) return

                // Extract series ID from URL
                const seriesMatch = href.match(/\/series\/([a-f0-9\-]+)\//i)
                if (!seriesMatch || !seriesMatch[1]) return

                const seriesId = seriesMatch[1]
                
                // Get title from text or find title in nearby elements
                let title = el.text().trim()
                if (!title) {
                    // Check if this link has an image or is wrapped in a parent with title
                    const parent = el.parent()
                    title = parent.find("h3, h2, h1, .title").first().text().trim()
                    if (!title) {
                        title = el.attr("title") || ""
                    }
                }

                if (!title || title.length < 2) return

                // Try to get cover image
                let image = ""
                const imgEl = el.find("img").first()
                if (imgEl.length > 0) {
                    image = imgEl.attr("src") || imgEl.attr("data-src") || ""
                }

                // Check if this result already exists
                const existingResult = results.find(r => r.id === seriesId)
                if (existingResult) return

                results.push({
                    id: seriesId,
                    title: title,
                    image: image,
                })
            } catch (e) {
                console.error("Error parsing search result:", e)
            }
        })

        // Fallback: if we didn't get good results, try parsing from the main search page
        if (results.length === 0) {
            const allSeriesUrl = `${this.api}/search`
            const allRes = await fetch(allSeriesUrl)
            if (allRes.ok) {
                const allHtml = await allRes.text()
                const all$ = LoadDoc(allHtml)
                
                all$("a[href*='/series/']").each((_: any, el: any) => {
                    try {
                        const href = el.attr("href") || ""
                        const seriesMatch = href.match(/\/series\/([a-f0-9\-]+)\//i)
                        if (!seriesMatch || !seriesMatch[1]) return

                        const seriesId = seriesMatch[1]
                        let title = el.text().trim()
                        
                        if (!title) {
                            const parent = el.parent()
                            title = parent.find("h3, h2, h1, .title").first().text().trim()
                        }

                        if (!title || title.length < 2) return
                        
                        // Filter based on search query
                        const queryLower = opts.query.toLowerCase()
                        const titleLower = title.toLowerCase()
                        if (!titleLower.includes(queryLower)) return

                        let image = ""
                        const imgEl = el.find("img").first()
                        if (imgEl.length > 0) {
                            image = imgEl.attr("src") || imgEl.attr("data-src") || ""
                        }

                        const existingResult = results.find(r => r.id === seriesId)
                        if (existingResult) return

                        results.push({
                            id: seriesId,
                            title: title,
                            image: image,
                        })
                    } catch (e) {
                        console.error("Error parsing fallback search result:", e)
                    }
                })
            }
        }

        return results.slice(0, 20) // Limit to first 20 results
    }

    /**
     * Find all chapters for a given manga
     * The id is the manga series UUID
     */
    async findChapters(seriesId: string): Promise<ChapterDetails[]> {
        const url = `${this.api}/series/${seriesId}/`

        const res = await fetch(url)
        if (!res.ok) {
            throw new Error(`Failed to fetch manga page: ${res.status}`)
        }

        const html = await res.text()
        const $ = LoadDoc(html)
        const chapters: ChapterDetails[] = []

        // Look for chapter links
        $("a[href*='/chapter/']").each((index: any, el: any) => {
            try {
                const href = el.attr("href") || ""
                if (!href.includes("/chapter/")) return

                // Extract chapter ID from URL
                const chapterMatch = href.match(/\/chapter\/([a-f0-9\-]+)/i)
                if (!chapterMatch || !chapterMatch[1]) return

                const chapterId = chapterMatch[1]
                let title = el.text().trim()

                // Extract chapter number from title
                let chapterNumber = "0"
                const chapterMatch2 = title.match(/chapter\s+(\d+(?:\.\d+)?)/i)
                if (chapterMatch2 && chapterMatch2[1]) {
                    chapterNumber = chapterMatch2[1]
                }

                // If no title, try to construct one
                if (!title) {
                    title = `Chapter ${chapterNumber}`
                }

                // Check if we already have this chapter
                const existingChapter = chapters.find(c => c.id === chapterId)
                if (existingChapter) return

                chapters.push({
                    id: chapterId,
                    url: `${this.api}/chapter/${chapterId}`,
                    title: title,
                    chapter: chapterNumber,
                    index: chapters.length,
                    language: "id",
                })
            } catch (e) {
                console.error("Error parsing chapter:", e)
            }
        })

        // Sort chapters by chapter number
        chapters.sort((a, b) => {
            const numA = parseFloat(a.chapter) || 0
            const numB = parseFloat(b.chapter) || 0
            return numA - numB
        })

        // Update indices after sorting
        chapters.forEach((chapter, index) => {
            chapter.index = index
        })

        if (chapters.length === 0) {
            throw new Error("No chapters found.")
        }

        return chapters
    }

    /**
     * Find chapter pages based on the chapter ID
     * Returns the pages that should be loaded for reading
     */
    async findChapterPages(chapterId: string): Promise<ChapterPage[]> {
        const url = `${this.api}/chapter/${chapterId}`

        const res = await fetch(url)
        if (!res.ok) {
            throw new Error(`Failed to fetch chapter page: ${res.status}`)
        }

        const html = await res.text()
        const $ = LoadDoc(html)
        const pages: ChapterPage[] = []

        // Look for manga page images
        $("img").each((index: any, el: any) => {
            try {
                let imgSrc = el.attr("src") || el.attr("data-src") || el.attr("data-lazy") || ""
                
                if (!imgSrc) return

                // Filter out non-manga images (ads, avatars, icons, etc.)
                if (imgSrc.includes("/icons/") || 
                    imgSrc.includes("/avatars/") ||
                    imgSrc.includes("/emotes/") ||
                    imgSrc.includes("profile") ||
                    imgSrc.includes("logo") ||
                    imgSrc.includes("ad") ||
                    imgSrc.includes("banner")) {
                    return
                }

                // Ensure absolute URL
                if (imgSrc.startsWith("/")) {
                    imgSrc = this.api + imgSrc
                } else if (!imgSrc.startsWith("http")) {
                    return
                }

                // Check for duplicate pages
                const existingPage = pages.find(p => p.url === imgSrc)
                if (existingPage) return

                pages.push({
                    url: imgSrc,
                    index: index,
                    headers: {
                        "Referer": `${this.api}/chapter/${chapterId}`,
                        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/119.0.0.0 Safari/537.36",
                    },
                })
            } catch (e) {
                console.error("Error parsing manga page:", e)
            }
        })

        // Sort pages by index
        pages.sort((a, b) => a.index - b.index)

        // Update indices to be sequential starting from 0
        pages.forEach((page, index) => {
            page.index = index
        })

        if (pages.length === 0) {
            throw new Error("No manga pages found for this chapter.")
        }

        return pages
    }
}
